/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    // Helper function to convert a point array to a string key for Set storage
    const pointToKey = (p) => p.join(',');

    // --- Check Generation ---

    // Set to store all unique points generated so far (starting with initial points)
    let allPoints = new Set();

    // Array to store the points explicitly at each generation level k (0, 1, 2, ...)
    // pointsAtGeneration[k] will be a Set of string keys for points present in generation k
    const pointsAtGeneration = [];

    // --- Generation k = 0 ---

    // Check if target is in initial points (k=0)
    const initialPointKeys = new Set(points.map(pointToKey));
    if (initialPointKeys.has(target.join(','))) {
        return 0;
    }

    // Initialize pointsAtGeneration[0] with initial points
    let currentGenerationPoints = new Set();
    points.forEach(p => {
        const key = pointToKey(p);
        allPoints.add(key);
        currentGenerationPoints.add(key);
    });
    pointsAtGeneration.push(currentGenerationPoints);

    // If there's only one initial point, no new points can ever be generated (since we need two *different* points)
    if (points.length < 2) {
        return -1;
    }

    // --- Generations k >= 1 ---

    let k = 1;
    while (true) {
        // Set to store unique points generated in the current generation k
        const nextGenerationPoints = new Set();

        // Convert Set keys back to arrays for easier processing
        const currentPointsArray = Array.from(allPoints).map(key => key.split(',').map(Number));

        // Get the set of points available up to generation k-1 (which is 'allPoints' now)
        // The problem states: "Consider from all points extracted from Generation 0 to Generation k-1"

        // We iterate over all pairs (a, b) where a and b are distinct points in allPoints
        const pointsList = Array.from(allPoints).map(key => key.split(',').map(Number));
        const n = pointsList.length;

        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                const p1 = pointsList[i];
                const p2 = pointsList[j];

                // Check if points are distinct coordinates. Since we iterate over distinct indices i != j, 
                // we must ensure they don't have identical coordinates, as per the rule: 
                // "two different points" means "different (x, y, z) coordinates".
                // Since 'allPoints' only stores unique coordinates, p1 and p2 derived from it are guaranteed to be distinct coordinates.

                // Calculate the midpoint c = [floor((x1 + x2) / 2), ...]
                const c = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const cKey = pointToKey(c);

                // Add to the set of points for generation k
                if (!allPoints.has(cKey)) {
                    nextGenerationPoints.add(cKey);
                    allPoints.add(cKey);
                }
            }
        }

        // Check if the target was generated in this step (i.e., is in nextGenerationPoints)
        if (nextGenerationPoints.has(target.join(','))) {
            return k;
        }

        // If no new points were generated, we can stop early (unless k=0 already covered it)
        if (nextGenerationPoints.size === 0) {
            return -1;
        }

        // Update generation history (although we only need 'allPoints' for the next step)
        pointsAtGeneration.push(nextGenerationPoints);
        k++;

        // Safety break for potentially infinite loops, though constraints suggest termination.
        // Given max coordinates are 6, the number of unique reachable points is finite.
        if (k > 1000) { 
             return -1;
        }
    }
}

